import{_ as o,c as e,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Ultraworkモード：ワンクリックで全機能を有効化 | oh-my-opencode","description":"oh-my-opencodeのUltraworkモードとコア機能を学びます。ultraworkキーワードの使用方法、有効化時の動作変化、並列探索メカニズム、強制完了検証、エージェント連携などについて解説し、すべての高度な機能を素早く有効化する方法を習得します。","frontmatter":{"title":"Ultraworkモード：ワンクリックで全機能を有効化 | oh-my-opencode","sidebarTitle":"ワンクリックで全機能を有効化","subtitle":"Ultraworkモード：ワンクリックで全機能を有効化","description":"oh-my-opencodeのUltraworkモードとコア機能を学びます。ultraworkキーワードの使用方法、有効化時の動作変化、並列探索メカニズム、強制完了検証、エージェント連携などについて解説し、すべての高度な機能を素早く有効化する方法を習得します。","tags":["ultrawork","バックグラウンドタスク","エージェント連携"],"prerequisite":["start-installation","start-sisyphus-orchestrator"],"order":30},"headers":[],"relativePath":"ja/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md","filePath":"ja/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"}'),l={name:"ja/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"};function d(i,t,s,n,c,u){return a(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="ultraworkモード-ワンクリックで全機能を有効化" tabindex="-1">Ultraworkモード：ワンクリックで全機能を有効化 <a class="header-anchor" href="#ultraworkモード-ワンクリックで全機能を有効化" aria-label="Permalink to &quot;Ultraworkモード：ワンクリックで全機能を有効化&quot;">​</a></h1><h2 id="この章で学べること" tabindex="-1">この章で学べること <a class="header-anchor" href="#この章で学べること" aria-label="Permalink to &quot;この章で学べること&quot;">​</a></h2><ul><li>一言でoh-my-opencodeのすべての高度な機能を有効化する</li><li>複数のAIエージェントを本物のチームのように並列で動作させる</li><li>複数のエージェントとバックグラウンドタスクの手動設定を回避する</li><li>Ultraworkモードの設計哲学とベストプラクティスを理解する</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><p>開発プロセスで次のような状況に遭遇したことはありませんか？</p><ul><li><strong>機能が多くて使い方がわからない</strong>：10個の専門エージェント、バックグラウンドタスク、LSPツールがあるが、素早く有効化する方法がわからない</li><li><strong>手動設定が必要</strong>：複雑なタスクのたびにエージェント、バックグラウンド並列実行などの設定を手動で指定する必要がある</li><li><strong>エージェント連携が非効率</strong>：エージェントをシリアルに呼び出し、時間とコストを浪費している</li><li><strong>タスクが途中で停滞する</strong>：エージェントにタスクを完了させる十分な動機と制約がない</li></ul><p>これらがoh-my-opencodeの真の威力を発揮するのを妨げています。</p><h2 id="コアコンセプト" tabindex="-1">コアコンセプト <a class="header-anchor" href="#コアコンセプト" aria-label="Permalink to &quot;コアコンセプト&quot;">​</a></h2><p><strong>Ultraworkモード</strong>はoh-my-opencodeの「ワンクリック全員有効化」メカニズムです。</p><div class="info custom-block"><p class="custom-block-title">Ultraworkモードとは？</p><p>Ultraworkモードはキーワードでトリガーされる特別な動作モードです。プロンプトに<code>ultrawork</code>または省略形の<code>ulw</code>を含めると、システムは自動的にすべての高度な機能を有効化します：並列バックグラウンドタスク、深層探索、強制完了、マルチエージェント連携など。</p></div><h3 id="設計哲学" tabindex="-1">設計哲学 <a class="header-anchor" href="#設計哲学" aria-label="Permalink to &quot;設計哲学&quot;">​</a></h3><p>Ultraworkモードは次のコア原則に基づいています（<a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer">Ultrawork Manifesto</a>から）：</p><table tabindex="0"><thead><tr><th>原則</th><th>説明</th></tr></thead><tbody><tr><td><strong>人間の介入は失敗のシグナル</strong></td><td>AIの出力を絶えず修正する必要がある場合、システム設計に問題があることを示している</td></tr><tr><td><strong>区別できないコード</strong></td><td>AIが書いたコードはシニアエンジニアが書いたコードと区別がつかないべきである</td></tr><tr><td><strong>認知的負荷の最小化</strong></td><td>あなたは「何をするか」を言うだけでよく、エージェントが「どう実装するか」を担当する</td></tr><tr><td><strong>予測可能、継続的、委譲可能</strong></td><td>エージェントはコンパイラのように安定して信頼できるべきである</td></tr></tbody></table><h3 id="有効化メカニズム" tabindex="-1">有効化メカニズム <a class="header-anchor" href="#有効化メカニズム" aria-label="Permalink to &quot;有効化メカニズム&quot;">​</a></h3><p>システムが<code>ultrawork</code>または<code>ulw</code>キーワードを検出すると：</p><ol><li><strong>最大精度モードを設定</strong>：<code>message.variant = &quot;max&quot;</code></li><li><strong>Toast通知を表示</strong>：&quot;Ultrawork Mode Activated - Maximum precision engaged. All agents at your disposal.&quot;</li><li><strong>完全な指令を注入</strong>：エージェントに200行以上のULTRAWORK指令を注入します。これには以下が含まれます： <ul><li>実装を開始する前に100%の確実性を強制する</li><li>バックグラウンドタスクの並列使用を要求する</li><li>Category + Skillsシステムの使用を強制する</li><li>強制完了検証（TDDワークフロー）</li><li>「できない」という言い訳を一切禁止する</li></ul></li></ol><h2 id="実践してみよう" tabindex="-1">実践してみよう <a class="header-anchor" href="#実践してみよう" aria-label="Permalink to &quot;実践してみよう&quot;">​</a></h2><h3 id="ステップ1-ultraworkモードをトリガーする" tabindex="-1">ステップ1：Ultraworkモードをトリガーする <a class="header-anchor" href="#ステップ1-ultraworkモードをトリガーする" aria-label="Permalink to &quot;ステップ1：Ultraworkモードをトリガーする&quot;">​</a></h3><p>OpenCodeで<code>ultrawork</code>または<code>ulw</code>キーワードを含むプロンプトを入力します：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ultrawork REST APIを開発する</span></span></code></pre></div><p>またはより簡潔に：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ulw ユーザー認証を追加する</span></span></code></pre></div><p><strong>確認できること</strong>：</p><ul><li>インターフェースにToast通知が表示される：&quot;Ultrawork Mode Activated&quot;</li><li>エージェントの応答が &quot;ULTRAWORK MODE ENABLED!&quot; で始まる</li></ul><h3 id="ステップ2-エージェントの動作変化を観察する" tabindex="-1">ステップ2：エージェントの動作変化を観察する <a class="header-anchor" href="#ステップ2-エージェントの動作変化を観察する" aria-label="Permalink to &quot;ステップ2：エージェントの動作変化を観察する&quot;">​</a></h3><p>Ultraworkモードが有効化されると、エージェントは次のようになります：</p><ol><li><p><strong>コードベースを並列探索</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;既存のAPIパターンを検索&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;テストインフラストラクチャを検索&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;librarian&quot;, prompt=&quot;認証のベストプラクティスを検索&quot;, background=true)</span></span></code></pre></div></li><li><p><strong>Planエージェントを呼び出して作業計画を作成</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(subagent_type=&quot;plan&quot;, prompt=&quot;収集したコンテキストに基づいて詳細な計画を作成&quot;)</span></span></code></pre></div></li><li><p><strong>Category + Skillsを使用してタスクを実行</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(category=&quot;visual-engineering&quot;, load_skills=[&quot;frontend-ui-ux&quot;, &quot;playwright&quot;], ...)</span></span></code></pre></div></li></ol><p><strong>確認できること</strong>：</p><ul><li>複数のバックグラウンドタスクが同時に実行されている</li><li>エージェントが能動的に専門エージェント（Oracle、Librarian、Explore）を呼び出している</li><li>完全なテスト計画と作業分解</li><li>タスクが100%完了するまで継続的に実行される</li></ul><h3 id="ステップ3-タスク完了を検証する" tabindex="-1">ステップ3：タスク完了を検証する <a class="header-anchor" href="#ステップ3-タスク完了を検証する" aria-label="Permalink to &quot;ステップ3：タスク完了を検証する&quot;">​</a></h3><p>エージェントが完了すると次のようになります：</p><ol><li><strong>検証の証拠を提示</strong>：実際にテストを実行した出力、手動検証の説明</li><li><strong>すべてのTODOが完了したことを確認</strong>：事前に完了を宣言しない</li><li><strong>作業内容を要約</strong>：何をしたか、なぜそうしたかをリストアップ</li></ol><p><strong>確認できること</strong>：</p><ul><li>明確なテスト結果（「たぶんできる」ではなく）</li><li>すべての問題が解決されている</li><li>未完了のTODOリストがない</li></ul><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><p>上記の手順を完了したら、次のことを確認します：</p><ul><li>[ ] <code>ulw</code>を入力した後にToast通知が表示される</li><li>[ ] エージェントの応答が &quot;ULTRAWORK MODE ENABLED!&quot; で始まる</li><li>[ ] 並列バックグラウンドタスクが実行されているのを観察できる</li><li>[ ] エージェントがCategory + Skillsシステムを使用している</li><li>[ ] タスク完了後に検証の証拠がある</li></ul><p>いずれかの項目が通らない場合、次のことを確認します：</p><ul><li>キーワードが正しくスペルされているか（<code>ultrawork</code>または<code>ulw</code>）</li><li>メインセッション内で実行しているか（バックグラウンドタスクはモードをトリガーしない）</li><li>設定ファイルで関連機能が有効になっているか</li></ul><h2 id="いつ使うべきか" tabindex="-1">いつ使うべきか <a class="header-anchor" href="#いつ使うべきか" aria-label="Permalink to &quot;いつ使うべきか&quot;">​</a></h2><table tabindex="0"><thead><tr><th>シナリオ</th><th>Ultraworkを使用</th><th>通常モード</th></tr></thead><tbody><tr><td><strong>複雑な新機能</strong></td><td>✅ 推奨（マルチエージェント連携が必要）</td><td>❌ 効率が不十分な可能性がある</td></tr><tr><td><strong>緊急修正</strong></td><td>✅ 推奨（迅速な診断と探索が必要）</td><td>❌ コンテキストを見落とす可能性がある</td></tr><tr><td><strong>単純な修正</strong></td><td>❌ 過剰（リソースの浪費）</td><td>✅ 適している</td></tr><tr><td><strong>アイデアの迅速な検証</strong></td><td>❌ 過剰</td><td>✅ 適している</td></tr></tbody></table><p><strong>経験則</strong>：</p><ul><li>タスクが複数のモジュールまたはシステムに関わる → <code>ulw</code>を使用</li><li>コードベースを深く調査する必要がある → <code>ulw</code>を使用</li><li>複数の専門エージェントを呼び出す必要がある → <code>ulw</code>を使用</li><li>単一ファイルの小さな変更 → <code>ulw</code>は不要</li></ul><h2 id="注意点" tabindex="-1">注意点 <a class="header-anchor" href="#注意点" aria-label="Permalink to &quot;注意点&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">注意事項</p><p><strong>1. すべてのプロンプトで<code>ulw</code>を使用しないでください</strong></p><p>Ultraworkモードは大量の指令を注入するため、単純なタスクには過剰設計です。本当にマルチエージェント連携、並列探索、深層分析が必要な複雑なタスクにのみ使用してください。</p><p><strong>2. バックグラウンドタスクはUltraworkモードをトリガーしません</strong></p><p>キーワード検出器はバックグラウンドセッションをスキップし、モードが子エージェントに誤って注入されるのを防ぎます。Ultraworkモードはメインセッションでのみ有効です。</p><p><strong>3. Provider設定が正しいことを確認してください</strong></p><p>Ultraworkモードは複数のAIモデルが並列で動作することに依存しています。一部のProviderが設定されていないか利用できない場合、エージェントは専門エージェントを呼び出せない可能性があります。</p></div><h2 id="この章のまとめ" tabindex="-1">この章のまとめ <a class="header-anchor" href="#この章のまとめ" aria-label="Permalink to &quot;この章のまとめ&quot;">​</a></h2><p>Ultraworkモードはキーワードでトリガーされ、「一言で全機能を有効化」という設計目標を実現しています：</p><ul><li><strong>シンプルで使いやすい</strong>：<code>ulw</code>を入力するだけで有効化</li><li><strong>自動連携</strong>：エージェントが自動的に他のエージェントを呼び出し、バックグラウンドタスクを並列実行</li><li><strong>強制完了</strong>：完全な検証メカニズムにより100%の完了を保証</li><li><strong>設定不要</strong>：エージェントの優先度、並列制限などの手動設定は不要</li></ul><p>覚えておいてください：Ultraworkモードはエージェントを本物のチームのように動作させるためのもので、あなたは意図を表現するだけでよく、エージェントが実行を担当します。</p><h2 id="次の章の予告" tabindex="-1">次の章の予告 <a class="header-anchor" href="#次の章の予告" aria-label="Permalink to &quot;次の章の予告&quot;">​</a></h2><blockquote><p>次の章では <strong><a href="./../../platforms/provider-setup/">Provider設定</a></strong> を学びます。</p><p>学べること：</p><ul><li>Anthropic、OpenAI、Googleなど複数のProviderを設定する方法</li><li>マルチモデル戦略が自動的にダウングレードし、最適なモデルを選択する仕組み</li><li>Provider接続とクォータ使用をテストする方法</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日時：2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>Ultrawork設計哲学</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer"><code>docs/ultrawork-manifesto.md</code></a></td><td>1-198</td></tr><tr><td>キーワード検出器Hook</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/index.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/index.ts</code></a></td><td>12-100</td></tr><tr><td>ULTRAWORK指令テンプレート</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/constants.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/constants.ts</code></a></td><td>54-280</td></tr><tr><td>キーワード検出ロジック</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/detector.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/detector.ts</code></a></td><td>26-53</td></tr></tbody></table><p><strong>主要な定数</strong>：</p><ul><li><code>KEYWORD_DETECTORS</code>：キーワード検出器設定。ultrawork、search、analyzeの3つのモードを含む</li><li><code>CODE_BLOCK_PATTERN</code>：コードブロックの正規表現。コードブロック内のキーワードをフィルタリングするために使用</li><li><code>INLINE_CODE_PATTERN</code>：インラインコードの正規表現。インラインコード内のキーワードをフィルタリングするために使用</li></ul><p><strong>主要な関数</strong>：</p><ul><li><code>createKeywordDetectorHook()</code>：キーワード検出器Hookを作成し、UserPromptSubmitイベントを監視</li><li><code>detectKeywordsWithType()</code>：テキスト内のキーワードを検出し、タイプ（ultrawork/search/analyze）を返す</li><li><code>getUltraworkMessage()</code>：Ultraworkモードの完全な指令を生成（エージェントタイプに基づいてPlannerまたは通常モードを選択）</li><li><code>removeCodeBlocks()</code>：テキストからコードブロックを削除し、コードブロック内でキーワードが誤ってトリガーされるのを防ぐ</li></ul><p><strong>ビジネスルール</strong>：</p><table tabindex="0"><thead><tr><th>ルールID</th><th>ルール説明</th><th>マーク</th></tr></thead><tbody><tr><td>BR-4.8.4-1</td><td>&quot;ultrawork&quot;または&quot;ulw&quot;が検出されるとUltraworkモードを有効化</td><td>【事実】</td></tr><tr><td>BR-4.8.4-2</td><td>Ultraworkモードは<code>message.variant = &quot;max&quot;</code>を設定</td><td>【事実】</td></tr><tr><td>BR-4.8.4-3</td><td>UltraworkモードはToast通知を表示：&quot;Ultrawork Mode Activated&quot;</td><td>【事実】</td></tr><tr><td>BR-4.8.4-4</td><td>バックグラウンドタスクセッションはキーワード検出をスキップし、モードの注入を回避</td><td>【事実】</td></tr><tr><td>BR-4.8.4-5</td><td>非メインセッションではultraworkキーワードのみを許可し、他のモードの注入をブロック</td><td>【事実】</td></tr></tbody></table></details>`,54)])])}const g=o(l,[["render",d]]);export{h as __pageData,g as default};
